INSERT INTO tasks (title, description, category, status, priority, due_date) VALUES
  ('Contactar los 3 trials activos manualmente', 'Mensaje personalizado de Osvaldo a cada trial. No bot, no email — WhatsApp directo. Una conversación de 15 min puede convertir.', 'manual', 'todo', 1, '2026-06-21'),
  ('Cambiar destino anuncios Meta a app.kalyo.io/login', 'Editar TODAS las campañas activas en Meta Ads Manager. Cambiar URL destino de /embajadores/ a app.kalyo.io/login. Sin tocar presupuesto puede duplicar conversiones.', 'ads', 'todo', 1, '2026-06-21'),
  ('Verificar variante F corriendo en Botio', 'botio.dgx.agency/admin/experiments confirmar A y E muestran Retirada, F activa con 0 asignados. Enviar mensaje de prueba al número para verificar flujo de 2 turnos.', 'bot', 'todo', 1, '2026-06-21'),
  ('Activar trigger Sofía para visitantes de /pricing', 'Cursor psyplatform: cuando usuario visita /pricing 2+ veces en 24h sin suscribir, Sofía manda WhatsApp automático con oferta de trial.', 'kalyo', 'todo', 1, '2026-06-21'),
  ('Publicar Reel #1 — hook de dolor clínico', 'Hook: ¿Cuántas horas del domingo se te van en notas clínicas? Publicar jueves antes de 7pm. Caption con pregunta que invite comentario real.', 'ig', 'todo', 1, '2026-06-21'),
  ('Instalar Microsoft Clarity en kalyo.io', 'Agregar script Clarity al head de kalyo.io vía Cursor. En 48h tendrás grabaciones de sesiones mobile para ver dónde abandona el usuario.', 'landing', 'todo', 2, '2026-06-22'),
  ('Publicar artículo: Escala Hamilton HAM-A', 'Target keyword: escala hamilton ansiedad interpretación. CTA al final: Aplica el HAM-A en Kalyo gratis. Enlazar a PHQ-9 y Beck para clúster SEO.', 'contenido', 'todo', 2, '2026-06-22'),
  ('Crear funnel report GA4 para onboarding', 'GA4 539858946 → Explorar → Funnel: /register → /onboarding → /dashboard. Ver drop-off real de los 64 usuarios que pasan 28 segundos y se van.', 'kalyo', 'todo', 2, '2026-06-22'),
  ('Revisar primeras conversaciones con variante F', 'Filtrar conversaciones de hoy en admin. Ver si leads asignados a F responden sí al turno 1 y si el segundo turno se dispara correctamente.', 'bot', 'todo', 2, '2026-06-22'),
  ('Publicar Reel #2 — testimonio de usuaria real', 'Video 30-45 seg con Mónica Páez o Regina usando Kalyo en consulta. Sin guion, natural. Antes tardaba X horas, ahora Y minutos.', 'ig', 'todo', 2, '2026-06-22'),
  ('Diseñar wireframe mobile-first nueva home', 'Hero 3 segundos, CTA único Prueba 7 días, 3 bullets beneficio, 2 testimonios reales arriba del pliegue. Diseñar para mobile primero.', 'landing', 'todo', 2, '2026-06-23'),
  ('Crear audiencia Custom retargeting /pricing en Meta', 'Meta Ads → Audiencias Custom → URL contiene pricing → últimos 30 días. Campaña retargeting $5 USD/día. Copy: ¿Revisaste nuestros planes? Tu trial sigue disponible.', 'ads', 'todo', 2, '2026-06-23'),
  ('Publicar artículo: AUDIT test de alcoholismo', 'Target: test AUDIT alcoholismo clínica. Enlazar PHQ-9 y DASS-21 para clúster. CTA: demo del test en Kalyo.', 'contenido', 'todo', 2, '2026-06-23'),
  ('Analizar tasa de respuesta reactivación fantasmas', 'Supabase Botio → conversations donde ghost_reactivation.sent > 0. ¿Cuántos de los 103 fantasmas respondieron al mensaje de 2h? ¿Y al de 24h?', 'bot', 'todo', 2, '2026-06-23'),
  ('Rediseñar onboarding paso 1 — bienvenida personalizada', 'Cursor psyplatform: nuevo paso 1 con nombre del psicólogo + país + especialidad. Objetivo: que se sienta identificado en los primeros 10 segundos.', 'kalyo', 'todo', 2, '2026-06-23'),
  ('Publicar Reel #3 — antes/después gestión consulta', 'Así gestionaba mis notas antes de Kalyo vs. ahora. Split-screen o texto animado. Publicar sábado. Hashtags: #PsicologosColombia #ConsultorioPrivado.', 'ig', 'todo', 2, '2026-06-24'),
  ('Implementar nueva home mobile-first en Cursor', 'Construir nueva versión kalyo.io según wireframe. Priorizar: carga menor a 2 seg mobile, hero visible sin scroll, CTA único, social proof arriba del pliegue.', 'landing', 'todo', 2, '2026-06-24'),
  ('Optimizar meta-titles de 5 artículos existentes del blog', 'Para cada artículo actualizar title y meta description con keywords específicos. Ejemplo: PHQ-9: Cómo interpretar resultados | Kalyo. Impacto en CTR orgánico.', 'contenido', 'todo', 2, '2026-06-24'),
  ('Verificar métricas trials_activados por variante', 'admin/experiments → columna Trials activados. ¿Cuántos trials reales generó cada variante? Esa es la métrica que predice MRR, no leads capturados.', 'bot', 'todo', 2, '2026-06-24'),
  ('Handoff manual de leads calificados en pipeline', 'admin/conversations/pipeline → columna qualified. Para cada lead con más de 48h sin respuesta: mensaje personalizado de Osvaldo o Aleja. No automatizado.', 'manual', 'todo', 2, '2026-06-24'),
  ('Lanzar A/B test landing — actual vs nueva mobile-first', 'Split 50/50 entre landing actual y nueva versión. Métrica primaria: engagement rate. Dejar correr 7 días mínimo antes de declarar ganadora.', 'ads', 'todo', 2, '2026-06-25'),
  ('Implementar aha moment en onboarding paso 2', 'Cursor psyplatform: paso 2 muestra reporte PHQ-9 generado con datos demo en vivo. El psicólogo ve lo que Kalyo hace sin explorar. Objetivo: 45-60 seg en este paso.', 'kalyo', 'todo', 2, '2026-06-25'),
  ('Publicar artículo: PCL-5 estrés postraumático — guía completa', 'Expandir artículo existente que ya tiene 7:10 min de sesión — el mejor del blog. Agregar subescalas DSM-5, tabla puntuaciones, casos clínicos LATAM.', 'contenido', 'todo', 2, '2026-06-25'),
  ('Analizar rendimiento semana 1 de Reels', 'admin/kpis/instagram → top posts. Ver reach, saves y comentarios de los 3 Reels publicados. El de mayor watch time → replicar su estructura la semana siguiente.', 'ig', 'todo', 2, '2026-06-25'),
  ('Crear landing específica /mx para México', 'Cursor kalyo.io: /mx con copy adaptado — pesos MXN, NOM-004, ejemplos México. México tiene 150 usuarios en app pero solo 82 en landing.', 'bot', 'todo', 2, '2026-06-25'),
  ('Implementar onboarding paso 3 — primera acción guiada', 'Paso 3: guiar al psicólogo a crear su primer paciente de prueba o enviar su primer test digital. Completar flujo de 3 pasos con objetivo mayor a 90 seg total.', 'kalyo', 'todo', 2, '2026-06-26'),
  ('Revisar resultados retargeting /pricing después de 4 días', 'CTR mayor a 2% → escalar a $10/día. Si menor a 1% → cambiar copy del anuncio. La audiencia de 33 personas es pequeña pero de altísima intención de compra.', 'ads', 'todo', 2, '2026-06-26'),
  ('Publicar artículo: CD-RISC escala de resiliencia', 'Expandir con validación en LATAM, comparativa versiones 10 y 25 ítems. Target: resiliencia Connor-Davidson psicología clínica. Enlazar catálogo tests Kalyo.', 'contenido', 'todo', 2, '2026-06-26'),
  ('Publicar Reel + carousel combo — teaser + paso a paso', 'Reel 15 seg como teaser de configurar cuestionarios personalizados → carousel 5 slides con paso a paso. El Reel impulsa el alcance del carousel.', 'ig', 'todo', 2, '2026-06-26'),
  ('Enviar propuesta a Ana — WhatsApp add-on', 'Ana mencionó que pagaría por WhatsApp. Mensaje personalizado: Pro $29 + WhatsApp $20 = $49/mo. Crear coupon ANA20 en Stripe para ella.', 'manual', 'todo', 2, '2026-06-26'),
  ('Revisión semana 1 experimento B vs C vs D vs F', '7 días de data: ¿está F superando a D en trials_activados? Si D sigue ganando en la métrica real, es el ganador definitivo. Documentar hallazgos.', 'bot', 'todo', 2, '2026-06-27'),
  ('Revisar grabaciones Clarity — primera semana', 'Clarity → Recordings → filtrar mobile. Ver 10 primeras grabaciones. Identificar punto exacto de abandono en celular. Documentar para siguiente iteración.', 'landing', 'todo', 2, '2026-06-27'),
  ('Crear funnel report GA4 para nuevo onboarding', 'GA4 539858946 → Funnel: /register → paso1 → paso2 → /dashboard. Medir drop-off del nuevo flujo vs el de 28 segundos anterior.', 'kalyo', 'todo', 2, '2026-06-27'),
  ('Publicar artículo: Evaluación riesgo suicida — protocolos SAFE-T', 'Alta búsqueda entre psicólogos clínicos. Protocolos SAFE-T y Columbia Scale. Disclaimer profesional al inicio. Potencial de tráfico Colombia.', 'contenido', 'todo', 2, '2026-06-27'),
  ('Publicar Reel: qué se viene en Kalyo julio', '30 seg mostrando novedades: facturación SAT/DIAN, formulación de caso con IA, app móvil. Crea anticipación y muestra que el producto evoluciona.', 'ig', 'todo', 2, '2026-06-27'),
  ('Ajustar campañas Meta según resultados A/B test landing', 'Si nueva landing tiene más de 5 puntos de engagement → 100% tráfico a nueva versión. Si no hay diferencia → revisar el hero y CTA específicamente.', 'ads', 'todo', 2, '2026-06-28'),
  ('Activar secuencia nurturing post-registro en Botio', 'Cursor Botio: 3 mensajes automáticos primeros 3 días post-registro. Día 1: bienvenida. Día 2: ¿Ya aplicaste tu primer test? Día 3: caso uso real de usuaria.', 'bot', 'todo', 2, '2026-06-28'),
